import { json } from "@sveltejs/kit";
import { c as checkAuth } from "../../../../../chunks/adminAuth.js";
async function POST({ request, platform }) {
  if (!checkAuth(request, platform)) {
    return json({ error: "Unauthorized" }, { status: 401 });
  }
  const sitemapUrl = "https://firetempmail.com/sitemap.xml";
  try {
    const res = await fetch(`https://www.google.com/ping?sitemap=${encodeURIComponent(sitemapUrl)}`);
    return json({
      success: true,
      pinged: true,
      status: res.status
    });
  } catch (err) {
    return json({
      success: false,
      pinged: false,
      error: "Failed to ping Google"
    }, { status: 502 });
  }
}
export {
  POST
};
